package taskengine

import (
	"fmt"
	"strings"
	"testing"

	"github.com/jackc/pgx/v5/pgtype"

	dbgen "github.com/sargunv/tend/server/internal/database/gen"
)

func nullOverdueAction(a dbgen.OverdueAction) dbgen.NullOverdueAction {
	return dbgen.NullOverdueAction{OverdueAction: a, Valid: true}
}

// TestValidateOverdueActionRuleMatrix covers the full behavior matrix:
// every recurrence type × every overdue action.
func TestValidateOverdueActionRuleMatrix(t *testing.T) {
	recurrenceTypes := []dbgen.RecurrenceType{
		dbgen.RecurrenceTypeOneOff,
		dbgen.RecurrenceTypeOnDependency,
		dbgen.RecurrenceTypeCompletionBased,
		dbgen.RecurrenceTypeFixedNonAccumulating,
		dbgen.RecurrenceTypeFixedAccumulating,
	}

	// want[action][recurrenceType] = "" if valid, else substring of expected error.
	advanceRequiresRecurring := map[dbgen.RecurrenceType]string{
		dbgen.RecurrenceTypeOneOff:               "requires a recurring task",
		dbgen.RecurrenceTypeOnDependency:         "requires a recurring task",
		dbgen.RecurrenceTypeCompletionBased:      "",
		dbgen.RecurrenceTypeFixedNonAccumulating: "",
		dbgen.RecurrenceTypeFixedAccumulating:    "not supported on fixed_accumulating",
	}
	// set_status and clear_due_date are valid on every task type with a due date.
	allValid := map[dbgen.RecurrenceType]string{
		dbgen.RecurrenceTypeOneOff:               "",
		dbgen.RecurrenceTypeOnDependency:         "",
		dbgen.RecurrenceTypeCompletionBased:      "",
		dbgen.RecurrenceTypeFixedNonAccumulating: "",
		dbgen.RecurrenceTypeFixedAccumulating:    "",
	}

	want := map[dbgen.OverdueAction]map[dbgen.RecurrenceType]string{
		dbgen.OverdueActionAdvanceRecurrence: advanceRequiresRecurring,
		dbgen.OverdueActionSetStatus:         allValid,
		dbgen.OverdueActionClearDueDate:      allValid,
	}

	for _, action := range []dbgen.OverdueAction{
		dbgen.OverdueActionAdvanceRecurrence,
		dbgen.OverdueActionSetStatus,
		dbgen.OverdueActionClearDueDate,
	} {
		for _, rt := range recurrenceTypes {
			name := fmt.Sprintf("%s on %s", action, rt)
			t.Run(name, func(t *testing.T) {
				statusName := pgtype.Text{}
				if action == dbgen.OverdueActionSetStatus {
					statusName = pgtype.Text{String: "done", Valid: true}
				}
				err := ValidateOverdueActionRule(
					pgtype.Int4{Int32: 0, Valid: true},
					nullOverdueAction(action),
					statusName,
					rt,
					true, // hasDue
				)
				errContains := want[action][rt]
				if errContains == "" {
					if err != nil {
						t.Fatalf("unexpected error: %v", err)
					}
					return
				}
				if err == nil {
					t.Fatalf("expected error containing %q, got nil", errContains)
				}
				if !strings.Contains(err.Error(), errContains) {
					t.Errorf("error %q does not contain %q", err.Error(), errContains)
				}
			})
		}
	}
}

func TestValidateOverdueActionRule(t *testing.T) {
	tests := []struct {
		name           string
		afterDays      pgtype.Int4
		action         dbgen.NullOverdueAction
		statusName     pgtype.Text
		recurrenceType dbgen.RecurrenceType
		hasDue         bool
		wantErr        bool
		errContains    string
	}{
		// ─── No rule ─────────────────────────────────────────────────────────────────
		{
			name:           "nil rule always valid",
			action:         dbgen.NullOverdueAction{Valid: false},
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         false,
			wantErr:        false,
		},
		// ─── Due date requirement applies to every action ───────────────────────────
		{
			name:           "advance_recurrence requires due date",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeCompletionBased,
			hasDue:         false,
			wantErr:        true,
			errContains:    "requires a due date",
		},
		{
			name:           "set_status requires due date",
			action:         nullOverdueAction(dbgen.OverdueActionSetStatus),
			statusName:     pgtype.Text{String: "done", Valid: true},
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         false,
			wantErr:        true,
			errContains:    "requires a due date",
		},
		{
			name:           "clear_due_date requires due date",
			action:         nullOverdueAction(dbgen.OverdueActionClearDueDate),
			recurrenceType: dbgen.RecurrenceTypeOnDependency,
			hasDue:         false,
			wantErr:        true,
			errContains:    "requires a due date",
		},
		// ─── set_status requires a status name on every task type ───────────────────
		{
			name:           "set_status without status name on recurring task",
			action:         nullOverdueAction(dbgen.OverdueActionSetStatus),
			statusName:     pgtype.Text{Valid: false},
			recurrenceType: dbgen.RecurrenceTypeCompletionBased,
			hasDue:         true,
			wantErr:        true,
			errContains:    "status is required",
		},
		{
			name:           "set_status without status name on one_off task",
			action:         nullOverdueAction(dbgen.OverdueActionSetStatus),
			statusName:     pgtype.Text{Valid: false},
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         true,
			wantErr:        true,
			errContains:    "status is required",
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			err := ValidateOverdueActionRule(tc.afterDays, tc.action, tc.statusName, tc.recurrenceType, tc.hasDue)
			if tc.wantErr {
				if err == nil {
					t.Fatal("expected error, got nil")
				}
				if tc.errContains != "" && !strings.Contains(err.Error(), tc.errContains) {
					t.Errorf("error %q does not contain %q", err.Error(), tc.errContains)
				}
			} else if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}
		})
	}
}

