package taskengine

import (
	"fmt"

	"github.com/jackc/pgx/v5/pgtype"
	dbgen "github.com/sargunv/tend/server/internal/database/gen"
	"github.com/sargunv/tend/server/internal/types"
)

// ValidateOverdueActionRule checks that an overdue action rule is compatible
// with the task's recurrence type and due date configuration.
//
// The behavior matrix:
//   - set_status / clear_due_date: valid on any task type with a due date —
//     they only mutate the task itself and need no schedule to consult.
//   - advance_recurrence: valid only on completion_based and
//     fixed_non_accumulating tasks. One-off and on_dependency tasks have no
//     schedule to advance to, and fixed_accumulating tasks are handled by the
//     accumulating cron, which spawns missed occurrences automatically.

display.text:
package taskengine

import (
	"fmt"

	"github.com/jackc/pgx/v5/pgtype"
	dbgen "github.com/sargunv/tend/server/internal/database/gen"
	"github.com/sargunv/tend/server/internal/types"
)

// ValidateOverdueActionRule checks that an overdue action rule is compatible
// with the task's recurrence type and due date configuration.
//
// The behavior matrix:
//   - set_status / clear_due_date: valid on any task type with a due date —
//     they only mutate the task itself and need no schedule to consult.
//   - advance_recurrence: valid only on completion_based and
//     fixed_non_accumulating tasks. One-off and on_dependency tasks have no
//     schedule to advance to, and fixed_accumulating tasks are handled by the
//     accumulating cron, which spawns missed occurrences automatically.
func ValidateOverdueActionRule(
	afterDays pgtype.Int4,
	action dbgen.NullOverdueAction,
	statusName pgtype.Text,
	recurrenceType dbgen.RecurrenceType,
	hasDue bool,
) error {
	if !action.Valid {
		return nil // no rule, nothing to validate
	}
	if !hasDue {
		return types.ValidationError("overdue_action_rule requires a due date")
	}
	switch action.OverdueAction {
	case dbgen.OverdueActionAdvanceRecurrence:
		switch recurrenceType {
		case dbgen.RecurrenceTypeCompletionBased, dbgen.RecurrenceTypeFixedNonAccumulating:
			// supported
		case dbgen.RecurrenceTypeFixedAccumulating:
			return types.ValidationError(
				"advance_recurrence overdue action is not supported on fixed_accumulating tasks; " +
					"the accumulating cron handles missed occurrences automatically",
			)
		default:
			return types.ValidationError(
				"advance_recurrence overdue action requires a recurring task; " +
					"one_off and on_dependency tasks have no schedule to advance",
			)
		}
	case dbgen.OverdueActionSetStatus:
		if !statusName.Valid {
			return types.ValidationError("overdue_action_rule.status is required when action is set_status")
		}
	case dbgen.OverdueActionClearDueDate:
		// valid on any task type with a due date
	default:
		return types.ValidationError(fmt.Sprintf("invalid overdue action %q", action.OverdueAction))
	}
	return nil
}

